## Red Flags

These thoughts mean STOPâ€”you're rationalizing:

| Thought | Reality |
|---------|---------|
| "This is just a simple question" | Questions are tasks. Check for skills. |
| "I need more context first" | Skill check comes BEFORE clarifying questions. |
| "Let me explore the codebase first" | Skills tell you HOW to explore. Check first. |
| "I can check git/files quickly" | Files lack conversation context. Check for skills. |
| "Let me gather information first" | Skills tell you HOW to gather information. |
| "This doesn't need a formal skill" | If a skill exists, use it. |
| "I remember this skill" | Skills evolve. Read current version. |
| "This doesn't count as a task" | Action = task. Check for skills. |
| "The skill is overkill" | Simple things become complex. Use it. |
| "I'll just do this one thing first" | Check BEFORE doing anything. |
| "This feels productive" | Undisciplined action wastes time. Skills prevent this. |
| "I know what that means" | Knowing the concept â‰  using the skill. Invoke it. |

## Skill Priority

When multiple skills could apply, use this order:

1. **Process skills first** (brainstorming, debugging) - these determine HOW to approach the task
2. **Implementation skills second** (frontend-design, mcp-builder) - these guide execution

"Let's build X" â†’ brainstorming first, then implementation skills.
"Fix this bug" â†’ debugging first, then domain-specific skills.

## Skill Types

**Rigid** (TDD, debugging): Follow exactly. Don't adapt away discipline.

**Flexible** (patterns): Adapt principles to context.

The skill itself tells you which.

## User Instructions

Instructions say WHAT, not HOW. "Add X" or "Fix Y" doesn't mean skip workflows.

const assert = require("node:assert/strict");
const fs = require("node:fs");
const vm = require("node:vm");

const tests = [];

function test(name, fn) {
  tests.push({ name, fn });
}

function loadPocketLedger() {
  const html = fs.readFileSync("index.html", "utf8");
  const scripts = [...html.matchAll(/<script>([\s\S]*?)<\/script>/g)].map((match) => match[1]);
  const appScript = scripts.find((script) => script.includes("window.PocketLedger"));

  assert.ok(appScript, "index.html should expose window.PocketLedger for behavior tests");

  const context = {
    console,
    Intl,
    Date,
    Math,
    window: {},
    document: { addEventListener() {} },
    localStorage: {
      getItem() {
        return null;
      },
      setItem() {},
    },
  };

  vm.createContext(context);
  vm.runInContext(appScript, context);
  return context.window.PocketLedger;
}

test("normalizes a EUR amount to integer cents", () => {
  const ledger = loadPocketLedger();

  const expense = ledger.normalizeExpense(
    { amount: "12.30", category: " Groceries ", date: "2026-07-08", note: " lunch " },
    () => "fixed-id",
    () => "2026-07-08T10:00:00.000Z",
  );

  assert.equal(expense.id, "fixed-id");
  assert.equal(expense.amountCents, 1230);
  assert.equal(expense.category, "Groceries");
  assert.equal(expense.note, "lunch");
});

test("sums only expenses from the requested month", () => {
  const ledger = loadPocketLedger();

  const total = ledger.totalForMonth(
    [
      { date: "2026-07-01", amountCents: 450 },
      { date: "2026-07-31", amountCents: 1550 },
      { date: "2026-06-30", amountCents: 9999 },
    ],
    "2026-07",
  );

  assert.equal(total, 2000);
});

test("groups current-month totals by category", () => {
  const ledger = loadPocketLedger();

  const totals = ledger.categoryTotalsForMonth(
    [
      { date: "2026-07-01", category: "Groceries", amountCents: 450 },
      { date: "2026-07-02", category: "Transport", amountCents: 800 },
      { date: "2026-07-03", category: "Groceries", amountCents: 1550 },
      { date: "2026-06-30", category: "Groceries", amountCents: 9999 },
    ],
    "2026-07",
  );

  assert.deepEqual(
    Array.from(totals, ({ category, amountCents }) => ({ category, amountCents })),
    [
      { category: "Groceries", amountCents: 2000 },
      { category: "Transport", amountCents: 800 },
    ],
  );
});

test("serializes expenses to CSV with headers and escaped fields", () => {
  const ledger = loadPocketLedger();

  const csv = ledger.expensesToCsv([
