test("export button downloads every saved expense as a CSV file", () => {
  const html = fs.readFileSync("index.html", "utf8");
  const scripts = [...html.matchAll(/<script>([\s\S]*?)<\/script>/g)].map((match) => match[1]);
  const appScript = scripts.find((script) => script.includes("window.PocketLedger"));
  const listeners = {};
  const elements = {};
  const createdAnchors = [];
  const objectUrls = [];
  const revokedUrls = [];
  const blobs = [];
  const storedExpenses = [
    {
      id: "groceries-current",
      amountCents: 1230,
      category: "Groceries",
      date: "2026-07-08",
      note: "Market",
      createdAt: "2026-07-08T09:00:00.000Z",
    },
    {
      id: "transport-current",
      amountCents: 500,
      category: "Transport",
      date: "2026-07-07",
      note: "Bus",
      createdAt: "2026-07-07T09:00:00.000Z",
    },
  ];

  function element(id) {
    elements[id] = {
      id,
      value: "",
      textContent: "",
      innerHTML: "",
      style: {},
      listeners: {},
      dataset: {},
      disabled: false,
      addEventListener(type, handler) {
        this.listeners[type] = handler;
      },
      focus() {},
    };
    return elements[id];
  }

  [
    "expense-form",
    "amount",
    "category",
    "date",
    "note",
    "form-error",
    "expense-rows",
    "table-wrap",
    "empty-state",
    "expense-count",
    "month-total",
    "month-label",
    "category-filter",
    "category-totals",
    "csv-export",
  ].forEach(element);

  elements["expense-form"].reset = () => {};

  class FakeBlob {
    constructor(parts, options) {
      this.parts = parts;
      this.options = options;
      blobs.push(this);
    }
  }

  const context = {
    console,
    Blob: FakeBlob,
    FormData: class FakeFormData {
      entries() {
        return [];
      }
    },
    Intl,
    Date,
    Math,
    URL: {
      createObjectURL(blob) {
        objectUrls.push(blob);
        return "blob:expenses";
      },
      revokeObjectURL(url) {
        revokedUrls.push(url);
      },
    },
    window: {},
    document: {
      addEventListener(type, handler) {
        listeners[type] = handler;
      },
      body: {
        appendChild(anchor) {
          anchor.wasAppended = true;
        },
        removeChild(anchor) {
          anchor.wasRemoved = true;
        },
      },
      createElement(tagName) {
        assert.equal(tagName, "a");
        const anchor = {
          href: "",
          download: "",
          style: {},
          wasClicked: false,
          click() {
            this.wasClicked = true;
          },
        };
        createdAnchors.push(anchor);
        return anchor;
      },
      getElementById(id) {
        return elements[id];
      },
    },
    localStorage: {
      getItem() {
        return JSON.stringify(storedExpenses);
      },
      setItem() {},
    },
  };

  context.window.URL = context.URL;

  vm.createContext(context);
  vm.runInContext(appScript, context);
  listeners.DOMContentLoaded();

  assert.equal(elements["csv-export"].disabled, false);
  elements["csv-export"].listeners.click();

  assert.equal(blobs.length, 1);
  assert.equal(blobs[0].options.type, "text/csv;charset=utf-8");
  assert.match(blobs[0].parts[0], /Date,Category,Note,Amount EUR/);
  assert.match(blobs[0].parts[0], /Groceries/);
  assert.match(blobs[0].parts[0], /Transport/);
  assert.equal(createdAnchors[0].download, "pocketledger-expenses.csv");
  assert.equal(createdAnchors[0].href, "blob:expenses");
  assert.equal(createdAnchors[0].wasAppended, true);
  assert.equal(createdAnchors[0].wasClicked, true);
  assert.equal(createdAnchors[0].wasRemoved, true);
  assert.deepEqual(objectUrls, [blobs[0]]);
  assert.deepEqual(revokedUrls, ["blob:expenses"]);
});
